# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from collections import defaultdict, Counter
import threading
import numpy as np
from PIL import Image
import io
import os
import pickle
from sklearn.linear_model import LogisticRegression
from sklearn.model_selection import train_test_split

app = Flask(__name__)

lock = threading.Lock()

images = {}
labels = defaultdict(list)
aggregated_labels = {}
model = None
label_to_idx = {}
idx_to_label = {}


def load_image(image_bytes):
    return Image.open(io.BytesIO(image_bytes)).convert("RGB")


def image_to_features(img):
    arr = np.asarray(img.resize((64, 64)), dtype=np.float32) / 255.0
    return arr.flatten()


def aggregate_majority(image_id):
    votes = labels.get(image_id, [])
    if not votes:
        return None
    counts = Counter(votes)
    top_count = max(counts.values())
    winners = [label for label, cnt in counts.items() if cnt == top_count]
    return sorted(winners)[0]


@app.route("/images", methods=["POST"])
def upload_image():
    if "image" not in request.files:
        return jsonify({"error": "missing image file"}), 400
    f = request.files["image"]
    image_id = request.form.get("image_id")
    if not image_id:
        return jsonify({"error": "missing image_id"}), 400

    image_bytes = f.read()
    try:
        img = load_image(image_bytes)
    except Exception:
        return jsonify({"error": "invalid image"}), 400

    with lock:
        images[image_id] = image_bytes

    return jsonify({"status": "ok", "image_id": image_id})


@app.route("/labels", methods=["POST"])
def submit_label():
    data = request.get_json(force=True, silent=True) or {}
    image_id = data.get("image_id")
    annotator_id = data.get("annotator_id")
    label = data.get("label")

    if not image_id or not annotator_id or label is None:
        return jsonify({"error": "missing image_id, annotator_id, or label"}), 400

    with lock:
        if image_id not in images:
            return jsonify({"error": "unknown image_id"}), 404
        labels[image_id].append(label)
        aggregated = aggregate_majority(image_id)
        if aggregated is not None:
            aggregated_labels[image_id] = aggregated

    return jsonify({"status": "ok", "image_id": image_id, "majority_label": aggregated_labels.get(image_id)})


@app.route("/labels/<image_id>", methods=["GET"])
def get_aggregated_label(image_id):
    with lock:
        return jsonify({
            "image_id": image_id,
            "labels": labels.get(image_id, []),
            "majority_label": aggregated_labels.get(image_id)
        })


@app.route("/train", methods=["POST"])
def train():
    global model, label_to_idx, idx_to_label

    with lock:
        train_items = []
        for image_id, label in aggregated_labels.items():
            if image_id in images and label is not None:
                train_items.append((image_id, label))

        if not train_items:
            return jsonify({"error": "no aggregated labels available"}), 400

        X = []
        y = []
        unique_labels = sorted(set(label for _, label in train_items))
        label_to_idx = {label: i for i, label in enumerate(unique_labels)}
        idx_to_label = {i: label for label, i in label_to_idx.items()}

        for image_id, label in train_items:
            img = load_image(images[image_id])
            X.append(image_to_features(img))
            y.append(label_to_idx[label])

        X = np.array(X, dtype=np.float32)
        y = np.array(y, dtype=np.int64)

        model = LogisticRegression(max_iter=1000)
        model.fit(X, y)

    return jsonify({"status": "ok", "trained_samples": len(y), "classes": unique_labels})


@app.route("/predict/<image_id>", methods=["GET"])
def predict(image_id):
    with lock:
        if model is None:
            return jsonify({"error": "model not trained"}), 400
        if image_id not in images:
            return jsonify({"error": "unknown image_id"}), 404
        img = load_image(images[image_id])
        feat = image_to_features(img).reshape(1, -1)
        pred_idx = int(model.predict(feat)[0])
        pred_label = idx_to_label.get(pred_idx, str(pred_idx))
        probs = None
        if hasattr(model, "predict_proba"):
            proba = model.predict_proba(feat)[0]
            probs = {idx_to_label[i]: float(p) for i, p in enumerate(proba)}

    return jsonify({"image_id": image_id, "predicted_label": pred_label, "probabilities": probs})


@app.route("/status", methods=["GET"])
def status():
    with lock:
        return jsonify({
            "images": len(images),
            "labeled_images": len(aggregated_labels),
            "annotations": sum(len(v) for v in labels.values()),
            "model_trained": model is not None
        })


if __name__ == "__main__":
    port = int(os.environ.get("PORT", 5000))
    app.run(host="0.0.0.0", port=port)